// C3: Physical sensing components
instance SwingAngleEncoder : DTDFVocab:SensingComponent [
    base:desc "Swing‑angle encoder measuring the hoist swinging motion on the physical crane."
    DTDFVocab:producedData SwingAngleDataTransmitted
]

instance Anemometer : DTDFVocab:SensingComponent [
    base:desc "Anemometer measuring wind speed near the crane."
    DTDFVocab:producedData WindSpeedDataTransmitted
]

instance ArduinoBoard : DTDFVocab:SensingComponent [
    base:desc "Arduino measurement and control board that reads the swing‑angle encoder and anemometer and provides status feedback from motor drivers."
