instance WindSpeedData : DTDFVocab:Data [
    base:desc "Time‑stamped wind‑speed measurements stored in TimescaleDB."
    DTDFVocab:fromData WindSpeedDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler, ValidationEnabler
]

instance ArduinoStatusData : DTDFVocab:Data [
    base:desc "Status feedback from motor drivers and Arduino, logged with timestamps."
    DTDFVocab:fromData ArduinoStatusDataTransmitted
    DTDFVocab:inputTo TimescaleDBEnabler, ValidationEnabler
]

