instance CartStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Stepper motor driving the crane cart along the gantry."
]

instance HoistStepperMotor : DTDFVocab:ActingComponent [
    base:desc "Stepper motor raising and lowering the hoist."
]

instance ElectromagnetActuator : DTDFVocab:ActingComponent [
    base:desc "Electromagnet at the end of the hoist used to pick up pucks (containers)."
]

