]

instance GrafanaEnabler : DTDFVocab:Enabler [
    base:desc "Grafana dashboard container visualizing logged data and insights."
    DTDFVocab:enables DataVisualizationService
]

instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "Eclipse Mosquitto MQTT broker facilitating publish/subscribe communication between DT services."
