]

instance TrajectoryGeneratorEnabler : DTDFVocab:Enabler [
    base:desc "Python ‘gantrylib’ module component that generates optimal swing‑free trajectories."
    DTDFVocab:enables TrajectoryGenerationService
]

instance SimulationEnabler : DTDFVocab:Enabler [
    base:desc "Real‑time simulation engine (Python) executing the dynamic model of the crane."
    DTDFVocab:enables RealTimeSimulationService
]

instance ValidationEnabler : DTDFVocab:Enabler [
    base:desc "Continuous validation component comparing executed trajectories with simulated ones and raising alerts."
    DTDFVocab:enables ContinuousValidationService
]

